// ==========================
// INPUT
// ==========================
// Function node outputs:
//   output 1 -> ESS charge current
//   output 2 -> VRM notification

const voltage = msg.payload;

// ==========================
// TIME
// ==========================
const now = new Date();
const hour = now.getHours();
const minute = now.getMinutes();

// ==========================
// CONTEXT MEMORY
// ==========================
let boostActive = context.get("boostActive") || false;
const previousWindow = context.get("activeWindow") || "none";
const previousChargeCurrent = context.get("chargeCurrent") || 0;

function buildNotification(windowName, chargeCurrent, reason) {
    const text = `${windowName} | V=${voltage.toFixed(2)}V | ${chargeCurrent}A | ${reason}`;

    return {
        topic: "vrm-notification",
        payload: text,
        notification: {
            message: text,
            level: chargeCurrent > 0 ? "warning" : "info",
            timestamp: now.toISOString()
        }
    };
}

// ==========================
// TIME WINDOWS
// ==========================
const nightWindow = (hour >= 22 || hour < 6);

const morningWindow =
    (hour > 6 && hour < 11) ||
    (hour === 6) ||
    (hour === 11 && minute <= 59);

const eveningWindow = hour >= 17;

// ==========================
// NIGHT WINDOW: 22:00–05:59
// Always charge at 25A
// ==========================
if (nightWindow) {
    const chargeCurrent = 25;
    const windowName = "NIGHT";
    const notifyMsg =
        previousWindow !== windowName || previousChargeCurrent !== chargeCurrent
            ? buildNotification(windowName, chargeCurrent, "Night charging active")
            : null;

    context.set("boostActive", true);
    context.set("activeWindow", windowName);
    context.set("chargeCurrent", chargeCurrent);

    node.status({
        fill: "blue",
        shape: "dot",
        text: `${windowName} | V=${voltage.toFixed(2)}V | ${chargeCurrent}A`
    });

    msg.payload = chargeCurrent;
    return [msg, notifyMsg];
}

// ==========================
// HYSTERESIS THRESHOLDS
// ==========================
let onThreshold = null;
let offThreshold = null;
let windowName = null;

// Morning window
if (morningWindow) {
    onThreshold = 53.5;
    offThreshold = 53.8;
    windowName = "MORNING";
}
// Evening window
else if (eveningWindow) {
    onThreshold = 54.0;
    offThreshold = 54.4;
    windowName = "EVENING";
}
// Outside windows
else {
    node.status({
        fill: "grey",
        shape: "ring",
        text: `OUTSIDE WINDOW | V=${voltage.toFixed(2)}V`
    });
    return null;
}

// ==========================
// RESET STATE WHEN WINDOW CHANGES
// Prevent night state from leaking into morning/evening
// ==========================
if (previousWindow !== windowName) {
    boostActive = false;
}

// ==========================
// HYSTERESIS LOGIC
// ==========================
if (!boostActive && voltage < onThreshold) {
    boostActive = true;
}

if (boostActive && voltage > offThreshold) {
    boostActive = false;
}

// ==========================
// SAVE CONTEXT
// ==========================
context.set("boostActive", boostActive);
context.set("activeWindow", windowName);

// ==========================
// OUTPUT CURRENT
// ==========================
const chargeCurrent = boostActive ? 25 : 0;
const notifyMsg =
    chargeCurrent !== previousChargeCurrent
        ? buildNotification(
            windowName,
            chargeCurrent,
            chargeCurrent > 0 ? "Boost charging enabled" : "Boost charging disabled"
        )
        : null;

context.set("chargeCurrent", chargeCurrent);

// ==========================
// VISUAL INDICATOR
// ==========================
node.status({
    fill: boostActive ? "green" : "yellow",
    shape: "dot",
    text: `${windowName} | V=${voltage.toFixed(2)}V | ${chargeCurrent}A`
});

// ==========================
// SEND TO ESS
// ==========================
msg.payload = chargeCurrent;
return [msg, notifyMsg];
